// // This module compares two 8-bit inputs A and B and outputs three signals: A_neq_B (1 if A is not equal to B), A_leq_B (1 if A is less than or equal to B), and A_geq_B (1 if A is greater than or equal to B).
module comparator_8bit (
    input [7:0] A,
    input [7:0] B,
    output reg A_eq_B,
    output reg A_gt_B,
    output reg A_lt_B
);

always @(*) begin
    A_eq_B = (A == B);
    A_gt_B = (A > B);
    A_lt_B = (A < B);
end

endmodule
